<template>
    <section>
        <loader :is-visible="isLoading"></loader>
        <div class="col-sm-12 col-md-12 col-lg-12 col-xl-12 p-0 mt-2">
            <ValidationObserver ref="observer" v-slot="{ handleSubmit }">
                <form @submit.prevent="validateAndSubmit">
                    <div class="col-sm-12 col-md-12 col-lg-12 col-xl-12">
                        <div v-for="(item, index) in Mainleveldiv" :key="index"
                            class="row mt-50 mb-3 py-3 px-1 position-relative billingmainblock">
                            <div class="col-sm-12 col-md-6 col-lg-4 col-xl-4">
                                <div class="form-group">
                                    <label>{{ $t('Type') }}:
                                        <i class="text-danger" v-if="isManidatory">*</i></label>
                                    <ValidationProvider rules="required" v-slot="{ errors }">
                                        <select v-model="item.serviceName" @change="GetDDlSelectValue(item)"
                                        :disabled="mode === 'View'"
                                            :class="['form-control', { 'is-invalid': errors[0] }]">
                                            <option disabled value="">{{ $t('Select') }}</option>
                                            <option v-for="gitem in SelectType" :key="gitem.value" :value="gitem">
                                                {{ gitem.name }}
                                            </option>
                                        </select>
                                    </ValidationProvider>
                                </div>
                            </div>

                            <div class="col-sm-12 col-md-6 col-lg-4 col-xl-4" v-if="item.showIfAndDdl">
                                <div class="form-group">
                                    <label>{{ $t('If') }}:
                                        <i class="text-danger" v-if="isManidatory">*</i>
                                    </label>
                                    <ValidationProvider rules="required" v-slot="{ errors }">
                                        <select v-model="item.if"
                                            :class="['form-control', { 'is-invalid': errors[0] }]">
                                            <option value="">{{ $t('Select') }}</option>
                                            <option v-for="gitem in ServiceData" :key="gitem.value"
                                                :value="gitem.value">
                                                {{ gitem.name }}
                                            </option>
                                        </select>
                                    </ValidationProvider>
                                </div>
                            </div>

                            <div class="col-sm-12 col-md-6 col-lg-4 col-xl-4" v-if="item.showIfAndDdl">
                                <div class="form-group">
                                    <label>{{ $t('And') }}:
                                        <i class="text-danger" v-if="isManidatory">*</i>
                                    </label>
                                    <ValidationProvider rules="required" v-slot="{ errors }">
                                        <select v-model="item.and"
                                            :class="['form-control', { 'is-invalid': errors[0] }]">
                                            <option value="">{{ $t('Select') }}</option>
                                            <option v-for="gitem in ServiceData" :key="gitem.value"
                                                :value="gitem.value">
                                                {{ gitem.name }}
                                            </option>
                                        </select>
                                    </ValidationProvider>
                                </div>
                            </div>

                            <div class="col-sm-12 col-md-6 col-lg-4 col-xl-4"
                                v-if="item.showChargeDdl || item.showReplace">
                                <div class="form-group">
                                    <label>{{ $t('OverrideCharged') }}:
                                        <i class="text-danger" v-if="isManidatory">*</i>
                                    </label>
                                    <ValidationProvider rules="required" v-slot="{ errors, validate }">
                                        <div>
                                            <SearchableSelect
                                                :key="index + '-charged'"
                                                v-model="item.charged"
                                                :items="overrideChargeData"
                                                :max-visible-chips="3"
                                                :action-buttons="{ selectAll: true, clear: true }"
                                                :item-fields="['text']"
                                                :group-fields="['groupText']"
                                                :max-render-items="50"
                                                :lazy-load="true"
                                                :placeholder="$t('Select')"
                                                :min-search-length="0"
                                                :multiple="true"
                                                
                                                :class="{ 'border-danger': errors.length }"
                                                style="min-width: 300px"/>
                                            <!-- <Multiselect v-model="item.charged" :options="ChargeData" :multiple="true"
                                                :close-on-select="false" :clear-on-select="false"
                                                :preserve-search="true" :searchable="true" :show-no-results="false"
                                                :internal-search="true" label="name" track-by="value"
                                                :placeholder="$t('Select')" @blur="validate"
                                                :class="{ 'is-invalid': errors.length }" /> -->
                                            <span class="text-danger"></span>
                                        </div>
                                    </ValidationProvider>
                                </div>
                            </div>

                            <div class="col-sm-12 col-md-6 col-lg-4 col-xl-4"
                                v-if="item.showChargeDdl || item.showReplace">
                                <div class="form-group">
                                    <label>{{ $t('AlreadyCharged') }}:
                                        <i class="text-danger" v-if="isManidatory">*</i>
                                    </label>
                                    <ValidationProvider rules="required" v-slot="{ errors }">
                                        <select v-model="item.alreadyCharge" :disabled="mode === 'View'"
                                            :class="['form-control', { 'is-invalid': errors[0] }]">
                                            <option value="">{{ $t('Select') }}</option>
                                            <option v-for="gitem in ChargeData" :key="gitem.value" :value="gitem.value">
                                                {{ gitem.name }}
                                            </option>
                                        </select>
                                    </ValidationProvider>
                                </div>
                            </div>

                            <div class="col-sm-12 col-md-6 col-lg-4 col-xl-4" v-if="item.showReplace">
                                <div class="form-group">
                                    <label>{{ $t('ReplacingBy') }}:
                                        <i class="text-danger" v-if="isManidatory">*</i>
                                    </label>
                                    <ValidationProvider rules="required" v-slot="{ errors }">
                                        <select v-model="item.replaceBy" :disabled="mode === 'View'"
                                            :class="['form-control', { 'is-invalid': errors[0] }]">
                                            <option value="">{{ $t('Select') }}</option>
                                            <option v-for="gitem in WorkCodeReplaceBy" :key="gitem.value"
                                                :value="gitem.value">
                                                {{ gitem.name }}
                                            </option>
                                        </select>
                                    </ValidationProvider>
                                </div>
                            </div>

                            <div class="col-sm-12 col-md-6 col-lg-4 col-xl-4">
                                <div class="form-group">
                                    <label>{{ $t('DayLimit') }}:
                                        <i class="text-danger" v-if="isManidatory">*</i>
                                    </label>
                                    <ValidationProvider rules="required" v-slot="{ errors }">
                                        <input type="number" v-model="item.dayLimit" class="form-control" :disabled="mode === 'View'"
                                            :class="['form-control', { 'is-invalid': errors[0] }]" />
                                    </ValidationProvider>
                                </div>
                            </div>

                            <div class="col-sm-12 col-md-6 col-lg-4 col-xl-4">
                                <div class="form-group">
                                    <label>{{ $t('Status') }}:
                                        <i class="text-danger" v-if="isManidatory">*</i>
                                    </label>
                                    <ValidationProvider rules="required" v-slot="{ errors }">
                                        <select v-model="item.status" :disabled="mode === 'View'"
                                            :class="['form-control', { 'is-invalid': errors[0] }]">
                                            <option value="">{{ $t('Select') }}</option>
                                            <option v-for="s in SelectStatus" :key="s.value" :value="s.value">
                                                {{ s.name }}
                                            </option>
                                        </select>
                                    </ValidationProvider>
                                </div>
                            </div>

                            <div class="deleteblock" v-if="mode !== 'View'">
                                <a @click="deleteRow(index)"><em class="fa fa-trash-o text-danger"></em></a>
                            </div>
                        </div>
                    </div>

                    <div class="col-12 p-0 mb-2">
                        <div class="row flex-row-reverse">
                        <div class="col-lg-6 text-right ">
                                <button type="submit" class="btn btn-success"  v-if="mode !== 'View'"><i class="fa fa-save pr-2"></i>{{ $t('Save')}}</button>
                        </div>
                        <div class="col-lg-6"><div class="mandatory py-2">{{ $t('MandatoryString') }}</div></div>
                        </div>
                    </div>
                </form>
            </ValidationObserver>
        </div>
    </section>
</template>

<script>
import { extend, ValidationObserver, ValidationProvider } from 'vee-validate';
import DataService from '../../../services/DataService';
import SearchableSelect from '@/components/Common/SearchableSelect.vue';

export default {
    components: {
        extend,
        ValidationObserver,
        ValidationProvider,
        SearchableSelect
    },
    props: {
        configurationId: {
            type: String,
            default: null
        },
        mode: {
            type: String,
            default: 'Edit'
        },
        clientId: {
            type: Number,
            default: false
        }
    },
    data() {
        return {
            hideDeleteButton: false,
            countIndex: 0,
            isManidatory: true,
            isLoading: false,
            selectedDdlValues: 0,
            Mainleveldiv: [
                {
                    id: 0,
                    serviceName: "",
                    charge_Purge: 0,
                    if: "",
                    and: "",
                    charged: [],
                    alreadyCharge: "",
                    replaceBy: '',
                    dayLimit: "",
                    status: "",
                    config_Id: this.configurationId,
                    showIfAndDdl: false,
                    showChargeDdl: false,
                    showReplace: false
                }
            ],

            SelectType: [
                { name: "Purge Record", value: 1 },
                { name: "Purge Charge", value: 2 },
                { name: "Override Charge", value: 3 }
            ],
            SelectStatus: [
                { name: this.$t("Active"), value: 1001 },
                { name: this.$t("Inactive"), value: 1002 }
            ],
            ServiceData: [],
            WorkCodeReplaceBy: [],
            ChargeData: [],
        };
    },

    created:async function() {
        await this.GetServiceList();
        await this.GetDdlWorkCode();
        await this.GetDropDownDataByCompanyId();
        await this.GetOverrideChargeList();
    },

    methods: {
        async GetOverrideChargeList() {
            const url = `configurationId=${this.configurationId}&clientId=${this.clientId}`;
            const response = await DataService.GetOverrideChargeList(url);

            if (response?.data?.length) {
                this.Mainleveldiv = response.data.map(item => {
                    const row = {
                        serviceName: this.SelectType.find(
                            x => x.value === item.charge_purge
                        ) || "",

                        if: item.service_id_from,
                        and: item.service_id_to,

                        charged: item.charge_when, 
                        // this.ChargeData.filter(
                        //     c => c.value === item.charge_when
                        // ),

                        alreadyCharge: item.charge_replace,
                        replaceBy: item.charge_replace_by,

                        dayLimit: item.day_limit,
                        status: item.status_id,

                        // default hidden
                        showIfAndDdl: false,
                        showChargeDdl: false,
                        showReplace: false
                    };

                    // 🔥 APPLY SAME DROPDOWN LOGIC
                    if (row.serviceName) {
                        this.GetDDlSelectValue(row);
                    }

                    return row;
                });
            } else {
                this.Mainleveldiv = [this.getEmptyRow()];
            }
        },
        GetDDlSelectValue(item) {
            const selectedName = item.serviceName.name;
            this.selectedDdlValues = item.serviceName.value;

            item.showIfAndDdl = false;
            item.showChargeDdl = false;
            item.showReplace = false;

            const config = {
                "Purge Record": () => { item.showIfAndDdl = true; },
                "Purge Charge": () => { item.showChargeDdl = true; },
                "Override Charge": () => {
                    item.showChargeDdl = true;
                    item.showReplace = true;
                }
            };

            if (config[selectedName]) {
                config[selectedName]();
            }
        },

        async AddNewRow() {
            debugger
            var vm = this;
            const isValid = await this.$refs.observer.validate();
            if (!isValid) {
                vm.ShowAlert(vm.$t("MandatoryString"), "warning", vm.$t("Alert"));
                return;
            }
            this.countIndex++;
            this.hideDeleteButton = true;
            this.Mainleveldiv.push({
                id: 0,
                serviceName: "",
                charge_Purge: 0,
                if: "",
                and: "",
                charged: [],
                alreadyCharge: "",
                replaceBy: "",
                dayLimit: "",
                status: "",
                config_Id: this.configurationId,
                showIfAndDdl: false,
                showChargeDdl: false,
                showReplace: false,
                overrideChargeData:[]
            });
        },

        deleteRow(index) {
            debugger
            var vm = this;
            if (this.Mainleveldiv.length > 1) {
                vm.confirmR(vm.$t("ConfirmDelete"), true, (vm.$t("Delete") + "  " + vm.$t("OverrideCharge")), function () {
                    vm.Mainleveldiv.splice(index, 1);
                    vm.countIndex--;
                    vm.ShowAlert(vm.$t('DeletedSuccessfully', [vm.$t('OverrideCharge')]), "Success", true, vm.$t('Alert'));
                    vm.countIndex > 0 ? vm.hideDeleteButton = true : vm.hideDeleteButton = false;
                });
            }
        },

        GetServiceList: async function () {
            await DataService.GetServiceListByCompanyId().then((response) => {
                if (response.data && response.data.length > 0) {
                    this.ServiceData = response.data.map(item => ({
                        value: item.SERVICE_ID,
                        name: item.SERVICE_NAME
                    }));
                }
            });
        },

        GetDdlWorkCode: async function () {
            this.isLoading = true;
            const url = `clientId=${this.clientId}&configId=${this.configurationId || 0}`;
            await DataService.GetDdlWorkCodeListByClient(url).then((response) => {
                if (response.data && response.data.length > 0) {
                    this.overrideChargeData = response.data.map(item => ({
                        value: item.WORK_CODE_ID,
                        text: item.WORK_CODE
                    }));

                    this.ChargeData = response.data.map(item => ({
                        value: item.WORK_CODE_ID,
                        name: item.WORK_CODE
                    }));
                }
                this.isLoading = false;
            });
        },

        GetDropDownDataByCompanyId: async function() {
           const url = `clientId=${this.clientId}&configId=${this.configurationId || 0}&type=RULE`;
           await DataService.GetDdlWorkCodeListByClient(url).then((response) => {
                if (response.data && response.data.length > 0) {
                    this.WorkCodeReplaceBy = response.data.map(item => ({
                        value: item.WORK_CODE_ID,
                        name: item.WORK_CODE
                    }));
                }
                this.isLoading = false;
            });
        },
        async validateAndSubmit() {
            debugger
            const isValid = await this.$refs.observer.validate();
            if (!isValid) {
                this.ShowAlert(this.$t("FillTheRequiredFields"), "warning", this.$t("Alert"));
                return;
            }
            this.isLoading = true;
            const cleanedData = this.Mainleveldiv.map(item => ({
                ...item,
                charged: item.charged.map(c => c.value).join(','),
                serviceName: item.serviceName.value
            }));
            const jsonResult = JSON.stringify(cleanedData);
            const data = `Data=${jsonResult}`;
            debugger;
            DataService.SaveOverrideRule(data).then((response) => {
                debugger
                if (response.data) {
                    if (response.data === "INSERTED") {
                        this.ShowAlert(this.$t('AddedSuccess', [this.$t('OverrideCharge')]), "Success", true, this.$t('Alert'));
                    } else if (response.data === "UPDATED") {
                        this.ShowAlert(this.$t('UpdatedSuccess', [this.$t('OverrideCharge')]), "Success", true, this.$t('Alert'));
                    } else {
                        this.ShowAlert(this.$t("UnknownError"), "failure", this.$t('Alert'));
                    }
                }
                this.isLoading = false;
                this.Mainleveldiv = [
                    {
                        id: 0,
                        serviceName: "",
                        if: "",
                        and: "",
                        charged: [],
                        alreadyCharge: "",
                        replaceBy: "",
                        dayLimit: "",
                        status: "",
                        config_Id: this.configurationId,
                        showIfAndDdl: false,
                        showChargeDdl: false,
                        showReplace: false
                    }
                ];
            });
        }
    }
};
</script>
